#include <stdio.h>
int superEggDrop(int eggs, int floors) {
    int dp[eggs + 1][floors + 1];
    for (int i = 1; i <= eggs; i++) {
        for (int j = 1; j <= floors; j++) {
            if (j == 1) dp[i][j] = 1;
            else if (i == 1) dp[i][j] = j;
            else {
                int low = 1, high = j;
                while (low < high) {
                    int mid = (low + high) / 2;
                    if (dp[i - 1][mid - 1] < dp[i][j - mid]) low = mid + 1;
                    else high = mid;
                }
                dp[i][j] = 1 + dp[i - 1][low - 1];
            }
        }
    }
    return dp[eggs][floors];
}

