function superEggDrop(eggs, floors) {
    let dp = Array(eggs + 1).fill(0).map(() => Array(floors + 1).fill(0));
    for (let i = 1; i <= eggs; i++) {
        for (let j = 1; j <= floors; j++) {
            if (j == 1) dp[i][j] = 1;
            else if (i == 1) dp[i][j] = j;
            else {
                let low = 1, high = j;
                while (low < high) {
                    let mid = Math.floor((low + high) / 2);
                    if (dp[i - 1][mid - 1] < dp[i][j - mid]) low = mid + 1;
                    else high = mid;
                }
                dp[i][j] = 1 + dp[i - 1][low - 1];
            }
        }
    }
    return dp[eggs][floors];
}

